import subprocess
import os
import sys
import shutil
import json

def install_dependencies(requirements_file='requirements.txt'):
    if not os.path.exists(requirements_file):
        print(f"Requirements file {requirements_file} not found.")
        sys.exit(1)
    
    subprocess.run([sys.executable, '-m', 'pip', 'install', '--upgrade', 'pip'], check=True)
    subprocess.run([sys.executable, '-m', 'pip', 'install', '-r', requirements_file], check=True)

def run_tests():
    result = subprocess.run([sys.executable, '-m', 'unittest', 'discover'], capture_output=True, text=True)
    if result.returncode != 0:
        print("Tests failed:")
        print(result.stdout)
        print(result.stderr)
        sys.exit(1)
    else:
        print("All tests passed.")

def package_for_deployment(output_dir='dist'):
    if os.path.exists(output_dir):
        shutil.rmtree(output_dir)
    os.makedirs(output_dir)

    subprocess.run([sys.executable, 'setup.py', 'sdist', '--dist-dir', output_dir], check=True)
    print(f"Package created in {output_dir}")

def main():
    install_dependencies()
    run_tests()
    package_for_deployment()

if __name__ == "__main__":
    main()